import{_ as e,o as t,c as o,a3 as s}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 猪","description":"亥猪——乐观真诚，知足常乐","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 猪","description":"亥猪——乐观真诚，知足常乐"},"headers":[],"relativePath":"changshi/shengxiao/zhu.md","filePath":"changshi/shengxiao/zhu.md","lastUpdated":1779783531000}'),n={name:"changshi/shengxiao/zhu.md"};function r(i,a,p,h,c,l){return t(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="亥猪" tabindex="-1">亥猪 <a class="header-anchor" href="#亥猪" aria-label="Permalink to &quot;亥猪&quot;">​</a></h1><blockquote><p>地支「亥」· 亥时（21:00–23:00）· 五行属水 · 阴阳为阴</p></blockquote><p>猪温驯老实，乐观忠诚。亥时的猪睡得最酣。以前人们看某一家是否富有，常以是否饲养猪为标志。猪被认为全身是宝——毛鬃可以做刷子，为人类做出了重大的贡献。猪看似笨拙，实则豁达——活在当下，乐在当下。</p><h2 id="生肖故事-断腿求雨的义猪" tabindex="-1">生肖故事：断腿求雨的义猪 <a class="header-anchor" href="#生肖故事-断腿求雨的义猪" aria-label="Permalink to &quot;生肖故事：断腿求雨的义猪&quot;">​</a></h2><p>很久以前，人间惨遭大旱，庄稼都旱死了，百姓们食不果腹，一时间饿殍遍野。猪在参加生肖比赛时，看到人们跪倒一片在求雨，便上前询问。一位老人说：「再不下雨我们就都要饿死了！」</p><p>猪心生同情，对老人家说：「今天是生肖排位的日子，恐怕一时半会儿顾不上降雨。等我上了天宫，定将这里的情况如实相告。你们再等一等吧。」众人痛苦地说：「我们马上就要饿死了，哪还等得起呀！」</p><p>猪看到大家痛苦的样子，说道：「老人家，现在您将我的四条腿砍掉先充饥吧。我一定会帮助大家求来雨的！」老人连连摆手：「这怎么能行呢？今天你也要参加生肖排位，我把你的腿砍掉你可怎么去？」猪回答：「救命要紧！况且我本来就走得慢，估计到了也早被其他动物抢先了。」</p><p>人们含着泪砍掉了猪的四条腿，大家也因此获得一线生机。后来人们为了报答猪的恩情，纷纷求玉帝将猪列入十二生肖。玉帝听说这件事后深受感动，破例允许猪成为生肖——排在生肖榜的第十二位。</p><p><strong>生肖习俗</strong>：天津、河北等地春节贴「肥猪拱门」窗花——猪背驮聚宝盆，左右各一张，表示招财进宝。陕西婚俗「结婚送猪蹄」——「蹄来蹄去」谐音「体来体去」，表示两家人今后要密切往来。</p>',9)])])}const u=e(n,[["render",r]]);export{_ as __pageData,u as default};
